mapper.select:
SELECT COUNT(1) FROM question

    
        AND question_type = #{questionType}
    
    
        AND stem LIKE CONCAT('%', #{stem}, '%')
    
    
        AND course_id = #{courseId}
    
    
        AND chapter_id = #{chapterId}
    
    
        AND creator_id = #{creatorId}

SELECT q.*, c.course_name as courseName
FROM question q
LEFT JOIN course c ON q.course_id = c.id

    
        AND q.question_type = #{questionType}
    
    
        AND q.stem LIKE CONCAT('%', #{stem}, '%')
    
    
        AND q.course_id = #{courseId}
    
    
        AND q.chapter_id = #{chapterId}
    
    
        AND q.creator_id = #{creatorId}
    

ORDER BY q.create_time DESC
LIMIT #{pageSize} OFFSET #{offset}
